import { Image } from 'expo-image';
import { useState } from 'react';
import { TouchableOpacity, Modal } from 'react-native';

const ProductThumbnail = ({ productId, publicId }) => {
  const [modalVisible, setModalVisible] = useState(false);

  // URL Cloudinary avec transformation
  const thumbnailUrl = `https://res.cloudinary.com/afrimarket/image/upload/c_thumb,w_100,h_100,f_auto,q_auto/v1/products/${publicId}`;
  const fullUrl = `https://res.cloudinary.com/afrimarket/image/upload/w_800,f_auto,q_auto/v1/products/${publicId}`;

  return (
    <>
      <TouchableOpacity onPress={() => setModalVisible(true)}>
        <Image
          source={thumbnailUrl}
          style={{ width: 100, height: 100, borderRadius: 10 }}
          transition={200}
          placeholder={{ blurhash: 'LKO2?U%2Tw=w^n~jV?R*' }}
        />
      </TouchableOpacity>

      <Modal visible={modalVisible} transparent={false}>
        <Image
          source={fullUrl}
          style={{ flex: 1 }}
          contentFit="contain"
          transition={400}
        />
        <Button title="Fermer" onPress={() => setModalVisible(false)} />
      </Modal>
    </>
  );
};
```

**Explication :** `c_thumb,w_100,h_100` génère une vignette recadrée. `f_auto, q_auto` optimise le format et la qualité automatiquement. Au clic, on charge la version haute qualité.

