import { useState } from 'react';
import { FlatList, View, Text, ActivityIndicator } from 'react-native';
import { Image } from 'expo-image';
import { useInfiniteQuery } from '@tanstack/react-query';

const ProductList = () => {
  const [refreshing, setRefreshing] = useState(false);

  const { data, fetchNextPage, hasNextPage, isFetchingNextPage, refetch } = useInfiniteQuery({
    queryKey: ['products'],
    queryFn: ({ pageParam = 0 }) => fetchProducts(pageParam),
    getNextPageParam: (lastPage) => lastPage.nextCursor,
    initialPageParam: 0
  });

  const products = data?.pages.flatMap(page => page.items) || [];

  const renderItem = ({ item }) => (
    <View style={{ padding: 12, borderBottomWidth: 1, borderColor: '#eee' }}>
      <Image
        source={{ uri: item.imageUrl }}
        style={{ width: '100%', height: 200, borderRadius: 12 }}
        contentFit="cover"
        transition={300}
        recyclingKey={item.id}  // Important pour le recyclage
        placeholder={{ blurhash: item.blurhash }}
        cachePolicy="memory-disk"
        onLoadEnd={() => console.log('Image chargée:', item.id)}
      />
      <Text style={{ fontSize: 16, fontWeight: 'bold', marginTop: 8 }}>
        {item.name} - {item.price} FCFA
      </Text>
    </View>
  );

  const onEndReached = () => {
    if (hasNextPage && !isFetchingNextPage) {
      fetchNextPage();
    }
  };

  return (
    <FlatList
      data={products}
      renderItem={renderItem}
      keyExtractor={(item) => item.id}
      onEndReached={onEndReached}
      onEndReachedThreshold={0.5}
      refreshing={refreshing}
      onRefresh={async () => {
        setRefreshing(true);
        await refetch();
        setRefreshing(false);
      }}
      ListFooterComponent={isFetchingNextPage ? <ActivityIndicator size="large" /> : null}
      initialNumToRender={3}  // Nombre d'éléments initiaux
      maxToRenderPerBatch={5}
      windowSize={5}
    />
  );
};

const fetchProducts = async (cursor) => {
  const res = await fetch(`/api/products?cursor=${cursor}&limit=20`);
  return res.json();
};

export default ProductList;
```

**Points clés :**
- `recyclingKey` : garantit que l'image est correctement réinitialisée quand la vue est recyclée
- `initialNumToRender={3}` : ne rend que 3 items au départ
- `onEndReached` : déclenche le chargement suivant automatiquement
